+import java.io.IOException;
+import java.nio.file.Files;
+import java.nio.file.Path;
+import java.nio.file.Paths;
+import java.util.ArrayList;
+import java.util.Arrays;
+import java.util.HashSet;
+import java.util.List;
+import java.util.Optional;
+import java.util.Set;
+
 public class Main {
+    private static final String FLYWAY_FQCN = "org.flywaydb.core.Flyway";
+    private static final String FLUENT_CONFIGURATION_FQCN = "org.flywaydb.core.api.configuration.FluentConfiguration";
+    private static final Set<String> FLYWAY_MUTATORS = new HashSet<>(Arrays.asList(
+            "setDataSource",
+            "setClassLoader",
+            "setLocations",
+            "setValidateOnMigrate"
+    ));
+
     public static void main(String[] args) {
-
+        if (args.length != 1) {
+            throw new IllegalArgumentException("Expected a single source root path argument");
+        }
+
+        final Path sourceRootPath = Paths.get(args[0]);
+        try {
+            transform(sourceRootPath);
+        } catch (final IOException e) {
+            throw new RuntimeException(e);
+        }
     }
+
+    private static void transform(final Path sourceRootPath) throws IOException {
+        final SourceRoot sourceRoot = new SourceRoot(sourceRootPath);
+        final List<CompilationUnit> compilationUnits = sourceRoot.tryToParseParallelized();
+        for (final CompilationUnit compilationUnit : compilationUnits) {
+            if (compilationUnit == null) {
+                continue;
+            }
+            LexicalPreservingPrinter.setup(compilationUnit);
+            rewriteCompilationUnit(compilationUnit);
+            final Path filePath = sourceRootPath.resolve(compilationUnit.getStorage().orElseThrow(() ->
+                    new IllegalStateException("Missing compilation unit storage")).getPath());
+            Files.write(filePath, LexicalPreservingPrinter.print(compilationUnit).getBytes());
+        }
+    }
+
+    private static void rewriteCompilationUnit(final CompilationUnit compilationUnit) {
+        compilationUnit.findAll(BlockStmt.class).forEach(Main::rewriteBlock);
+        compilationUnit.findAll(ExpressionStmt.class).forEach(stmt -> {
+            final Optional<MethodCallExpr> maybeCall = stmt.getExpression().asMethodCallExpr().getScope().flatMap(scope -> Optional.empty());
+        });
+
+        compilationUnit.findAll(MethodCallExpr.class).stream()
+                .filter(Main::isFlywayMutator)
+                .forEach(Main::rewriteMutatorCall);
+        compilationUnit.findAll(ObjectCreationExpr.class).stream()
+                .filter(Main::isZeroArgFlywayConstruction)
+                .forEach(Main::rewriteFlywayConstruction);
+    }
+
+    private static void rewriteBlock(final BlockStmt blockStmt) {
+        final List<Statement> statements = new ArrayList<>(blockStmt.getStatements());
+        for (int i = 0; i < statements.size(); i++) {
+            final Statement statement = statements.get(i);
+            if (!statement.isExpressionStmt()) {
+                continue;
+            }
+            final Expression expression = statement.asExpressionStmt().getExpression();
+            if (!expression.isMethodCallExpr()) {
+                continue;
+            }
+            final MethodCallExpr call = expression.asMethodCallExpr();
+            if (!isFlywayMutator(call)) {
+                continue;
+            }
+            final Optional<VariableDeclarator> target = resolveFlywayVariable(call);
+            if (!target.isPresent()) {
+                continue;
+            }
+            final MethodCallExpr replacement = buildFlywayBuilderCall(target.get(), call);
+            target.get().setInitializer(replacement);
+            statement.remove();
+        }
+    }
+
+    private static void rewriteMutatorCall(final MethodCallExpr call) {
+        final Optional<VariableDeclarator> target = resolveFlywayVariable(call);
+        if (!target.isPresent()) {
+            return;
+        }
+        final MethodCallExpr replacement = buildFlywayBuilderCall(target.get(), call);
+        target.get().setInitializer(replacement);
+        call.getParentNode().ifPresent(Node::remove);
+    }
+
+    private static void rewriteFlywayConstruction(final ObjectCreationExpr creationExpr) {
+        final Optional<VariableDeclarator> maybeVar = creationExpr.findAncestor(VariableDeclarator.class);
+        if (!maybeVar.isPresent()) {
+            return;
+        }
+        final VariableDeclarator variable = maybeVar.get();
+        final MethodCallExpr builder = new MethodCallExpr(new MethodCallExpr(null, "Flyway.configure"), "load");
+        variable.setInitializer(builder);
+    }
+
+    private static MethodCallExpr buildFlywayBuilderCall(final VariableDeclarator variable, final MethodCallExpr call) {
+        final String methodName = call.getNameAsString();
+        final MethodCallExpr previous = variable.getInitializer().filter(Expression::isMethodCallExpr).map(Expression::asMethodCallExpr).orElse(null);
+        final MethodCallExpr builderRoot;
+        if (previous != null && isFlywayBuilder(previous)) {
+            builderRoot = previous;
+        } else {
+            builderRoot = new MethodCallExpr(null, "Flyway.configure");
+        }
+
+        final MethodCallExpr updated = builderRoot.clone();
+        if ("setDataSource".equals(methodName) && call.getArguments().size() == 1) {
+            updated.setScope(new MethodCallExpr(updated.getScope().orElse(null), "dataSource", call.getArguments()));
+        } else if ("setClassLoader".equals(methodName) && call.getArguments().size() == 1) {
+            updated.setScope(new MethodCallExpr(updated.getScope().orElse(null), "configure", call.getArguments()));
+        } else if ("setLocations".equals(methodName) && call.getArguments().size() == 1) {
+            updated.setScope(new MethodCallExpr(updated.getScope().orElse(null), "locations", call.getArguments()));
+        } else if ("setValidateOnMigrate".equals(methodName) && call.getArguments().size() == 1) {
+            updated.setScope(new MethodCallExpr(updated.getScope().orElse(null), "validateOnMigrate", call.getArguments()));
+        }
+        return new MethodCallExpr(updated, "load");
+    }
+
+    private static boolean isFlywayBuilder(final MethodCallExpr expr) {
+        return expr.toString().startsWith("Flyway.configure");
+    }
+
+    private static boolean isZeroArgFlywayConstruction(final ObjectCreationExpr expr) {
+        return expr.getArguments().isEmpty() && isTypeName(expr.getType(), FLYWAY_FQCN);
+    }
+
+    private static boolean isFlywayMutator(final MethodCallExpr expr) {
+        return FLYWAY_MUTATORS.contains(expr.getNameAsString()) && expr.getScope().isPresent();
+    }
+
+    private static Optional<VariableDeclarator> resolveFlywayVariable(final MethodCallExpr call) {
+        final Optional<VariableDeclarator> variable = call.findAncestor(VariableDeclarator.class);
+        if (!variable.isPresent()) {
+            return Optional.empty();
+        }
+        if (!isTypeName(variable.get().getType(), FLYWAY_FQCN)) {
+            return Optional.empty();
+        }
+        return Optional.of(variable.get());
+    }
+
+    private static boolean isTypeName(final ClassOrInterfaceType type, final String fqcn) {
+        return type.getNameAsString().equals(simpleName(fqcn));
+    }
+
+    private static String simpleName(final String fqcn) {
+        final int index = fqcn.lastIndexOf('.');
+        return index < 0 ? fqcn : fqcn.substring(index + 1);
+    }
 }
