@Bean(initMethod = "migrate")
public Flyway flyway() throws IOException {
	final Properties prop = new Properties();
	prop.load(NisAppConfig.class.getClassLoader().getResourceAsStream("db.properties"));

	final org.flywaydb.core.Flyway flyway = Flyway.configure(NisAppConfig.class.getClassLoader()).dataSource(this.dataSource()).locations(prop.getProperty("flyway.locations")).validateOnMigrate(Boolean.valueOf(prop.getProperty("flyway.validate"))).load();
	return flyway;
}

